         Create Spacecraft JSL;
         JSL.Tanks = {TankA}
         JSL.Thrusters = {ThrusterA}

         %% Added Mass Properties' lookup table files
         JSL.DryMass = 2440;
         JSL.MassPropertiesTableFilePath = '../include'
         JSL.ExtendedMassPropertiesModelType = 'Lookup'
         JSL.ExtendedMassPropertiesModel     = 'CenterOfMassAndMomentOfInertia'
         JSL.CenterOfMassTableFileName       = 'FakeLinearCM.table'
         JSL.MomentOfInertiaTableFileName    = 'FakeLinearMOI.table'

         Create ChemicalTank TankA
         TankA.Volume = 2.0
         TankA.FuelMass = 1500
         Create Thruster ThrusterA
         ThrusterA.Tank = {TankA}
         Create FiniteBurn fb1;
         fb1.Thrusters = {ThrusterA};
         ThrusterA.DecrementMass = true;

         %---------- Propagator ----------------
         Create Propagator EarthProp;
         Create ForceModel TorqueForces;
         EarthProp.FM = TorqueForces

         %---------- Reports -------------------
         Create ReportFile CM;
         CM.Filename = 'CM.report'
         Create ReportFile MOI;
         MOI = 'MOI.report'

         %---------- Mission Sequence ----------
         BeginMissionSequence;

         BeginFiniteBurn fb1(JSL);
            For loop = 1:14
               Report  CM JSL.TotalMass JSL.SystemCenterOfMassX JSL.SystemCenterOfMassY JSL.SystemCenterOfMassZ
               Report MOI JSL.SystemMomentOfInertiaXX JSL.SystemMomentOfInertiaXY JSL.SystemMomentOfInertiaXZ  ...
                          JSL.SystemMomentOfInertiaYY JSL.SystemMomentOfInertiaYZ JSL.SystemMomentOfInertiaZZ
               nextFuelMass = JSL.TankA.FuelMass - 100
               Propagate EarthProp(JSL) {JSL.TankA.FuelMass = nextFuelMass}
            EndFor
            Report  CM JSL.TotalMass JSL.SystemCenterOfMassX JSL.SystemCenterOfMassY JSL.SystemCenterOfMassZ
            Report MOI JSL.SystemMomentOfInertiaXX JSL.SystemMomentOfInertiaXY JSL.SystemMomentOfInertiaXZ  ...
                       JSL.SystemMomentOfInertiaYY JSL.SystemMomentOfInertiaYZ JSL.SystemMomentOfInertiaZZ

         EndFiniteBurn fb1(JSL); code>

TrackingFileSet — Examples
This example illustrates use of the TrackingFileSet object for simulation of DSN
      tracking data. Specification of the tracking configurations
      ( AddTrackingConfig ) is optional when running the
      estimator. If omitted, GMAT will attempt to automatically detect the
      tracking configurations present in the tracking data file. In this example, the frequency ramp table file dsn.ramp must be a preexisting ramp table. GMAT will
      not simulate ramp table records. Alternatively, the user may omit
      specification of a ramp table when simulating data. If the ramp table is
      omitted, the simulator will use the frequency specified on the Transmitter object attached to each GroundStation . Create TrackingFileSet dsnObs;

%Create objects referenced by dnsObs
Create GroundStation GDS CAN MAD;
Create Spacecraft EstSat;
Create AcceptFilter af;

dsnObs.AddTrackingConfig       = {{GDS, EstSat, GDS}, 'DSN_TCP'};
dsnObs.AddTrackingConfig       = {{CAN, EstSat, CAN}, 'DSN_TCP'};
dsnObs.AddTrackingConfig       = {{MAD, EstSat, MAD}, 'DSN_TCP', 'DSN_SeqRange'};
dsnObs.FileName                = {'dsn.gmd'};
dsnObs.RampTable               = {'dsn.ramp'};
dsnObs.UseLightTime            = True;
dsnObs.UseRelativityCorrection = False;
dsnObs.UseETminusTAI           = False;
dsnObs.SimRangeModuloConstant  = 67108864;
dsnObs.SimDopplerCountInterval = 10.; 
dsnObs.DataFilters             = {af};

BeginMissionSequence; This example illustrates use of the TrackingFileSet object for simulation of GPS_PosVec
      tracking data. This example assumes that GpsReceiver is a previously created instance of Receiver and
      has been attached to SimSat using the AddHardware method. Create TrackingFileSet PosVecObs;

PosVecObs.FileName          = {'posvec_obs.gmd'};
PosVecObs.AddTrackingConfig = {{SimSat.GpsReceiver}, 'GPS_PosVec'};
SimMeas.DataFilters         = {};

BeginMissionSequence;

